#!/bin/bash\n\n################################################################################\n# Script de Compilación para Termux - VERSIÓN ADMIN SOLAMENTE\n# Versión: 1.0.0\n# Descripción: Compila SOLO la versión Admin del Gestor de Créditos\n# Plataforma: Termux (Android)\n# Tiempo estimado: 40-50 minutos\n################################################################################\n\n# Colores para la salida\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nMAGENTA='\\033[0;35m'\nCYAN='\\033[0;36m'\nNC='\\033[0m' # No Color\n\n# Emojis\nCHECK=\"✅\"\nERROR=\"❌\"\nWARN=\"⚠️ \"\nINFO=\"ℹ️ \"\nHOURGLASS=\"⏳\"\nGEAR=\"🔧\"\nBUILD=\"🔨\"\nFILE=\"📁\"\nSUCCESS=\"🎉\"\n\n# Directorios\nPROJECT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nDIST_DIR=\"$PROJECT_DIR/dist\"\nAPK_DIR=\"$DIST_DIR/apks\"\nLOG_DIR=\"$DIST_DIR\"\nLOG_FILE=\"$LOG_DIR/compile-admin-termux.log\"\nREPORT_FILE=\"$LOG_DIR/admin-build-report-$(date +%Y%m%d_%H%M%S).txt\"\n\n# Variables de compilación\nAPP_NAME=\"Gestor de Créditos - Admin\"\nAPP_VERSION=\"1.0.0\"\nBUILD_DATE=$(date '+%Y-%m-%d %H:%M:%S')\nSTART_TIME=$(date +%s)\n\n# Función para imprimir con color\nprint_header() {\n    echo -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\n    echo -e \"${CYAN}$1${NC}\"\n    echo -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\n}\n\nprint_success() {\n    echo -e \"${GREEN}${CHECK} $1${NC}\"\n}\n\nprint_error() {\n    echo -e \"${RED}${ERROR} $1${NC}\"\n}\n\nprint_warning() {\n    echo -e \"${YELLOW}${WARN}$1${NC}\"\n}\n\nprint_info() {\n    echo -e \"${BLUE}${INFO}$1${NC}\"\n}\n\nprint_step() {\n    echo -e \"${MAGENTA}$1${NC}\"\n}\n\n# Función para registrar en log\nlog_message() {\n    echo \"[$(date '+%Y-%m-%d %H:%M:%S')] $1\" >> \"$LOG_FILE\"\n}\n\n# Función para manejar errores\nerror_exit() {\n    print_error \"$1\"\n    log_message \"ERROR: $1\"\n    exit 1\n}\n\n# Banner inicial\nclear\necho -e \"${MAGENTA}\"\necho \"╔═══════════════════════════════════════════════════════════════╗\"\necho \"║                                                               ║\"\necho \"║    GESTOR DE CRÉDITOS Y COBRANZAS - COMPILACIÓN TERMUX       ║\"\necho \"║                                                               ║\"\necho \"║              Script de Compilación - ADMIN ONLY               ║\"\necho \"║                                                               ║\"\necho \"║                    Versión 1.0.0                              ║\"\necho \"║                                                               ║\"\necho \"╚═══════════════════════════════════════════════════════════════╝\"\necho -e \"${NC}\"\necho \"\"\n\n# Información inicial\nprint_info \"Directorio del proyecto: $PROJECT_DIR\"\nprint_info \"Directorio de logs: $LOG_DIR\"\nprint_info \"Directorio de APKs: $APK_DIR\"\necho \"\"\n\n# Crear directorios necesarios\nmkdir -p \"$APK_DIR\"\nmkdir -p \"$LOG_DIR\"\n\n# Inicializar log\necho \"═══════════════════════════════════════════════════════════════\" > \"$LOG_FILE\"\necho \"Compilación de Gestor de Créditos - Versión Admin\" >> \"$LOG_FILE\"\necho \"Fecha: $BUILD_DATE\" >> \"$LOG_FILE\"\necho \"Plataforma: Termux (Android)\" >> \"$LOG_FILE\"\necho \"═══════════════════════════════════════════════════════════════\" >> \"$LOG_FILE\"\necho \"\" >> \"$LOG_FILE\"\n\nlog_message \"Iniciando compilación de versión Admin\"\n\n# PASO 1: Verificar Termux\nprint_header \"PASO 1: Verificando Termux\"\nif [ ! -d \"$PREFIX\" ]; then\n    error_exit \"Este script debe ejecutarse DENTRO de Termux\"\nfi\nprint_success \"Termux detectado correctamente\"\nlog_message \"Termux verificado\"\necho \"\"\n\n# PASO 2: Verificar Node.js y npm\nprint_header \"PASO 2: Verificando Dependencias\"\nif ! command -v node &> /dev/null; then\n    print_error \"Node.js no está instalado\"\n    log_message \"ERROR: Node.js no encontrado\"\n    read -p \"¿Deseas instalar Node.js? (s/n): \" -n 1 -r\n    echo\n    if [[ $REPLY =~ ^[Ss]$ ]]; then\n        print_step \"Instalando Node.js...\"\n        pkg install -y nodejs || error_exit \"Falló la instalación de Node.js\"\n        print_success \"Node.js instalado\"\n        log_message \"Node.js instalado correctamente\"\n    else\n        error_exit \"Node.js es requerido para compilar\"\n    fi\nelse\n    print_success \"Node.js: $(node --version)\"\n    log_message \"Node.js encontrado: $(node --version)\"\nfi\n\nif ! command -v npm &> /dev/null; then\n    error_exit \"npm no está instalado\"\nelse\n    print_success \"npm: $(npm --version)\"\n    log_message \"npm encontrado: $(npm --version)\"\nfi\n\nif ! command -v git &> /dev/null; then\n    print_warning \"git no está instalado, instalando...\"\n    pkg install -y git || error_exit \"Falló la instalación de git\"\n    print_success \"git instalado\"\n    log_message \"git instalado correctamente\"\nelse\n    print_success \"git: $(git --version)\"\n    log_message \"git encontrado: $(git --version)\"\nfi\n\necho \"\"\n\n# PASO 3: Limpiar caché\nprint_header \"PASO 3: Limpiando Caché\"\nprint_step \"Limpiando caché de npm...\"\nnpm cache clean --force >> \"$LOG_FILE\" 2>&1\nprint_success \"Caché limpiado\"\nlog_message \"Caché de npm limpiado\"\necho \"\"\n\n# PASO 4: Instalar dependencias del proyecto\nprint_header \"PASO 4: Instalando Dependencias del Proyecto\"\nprint_step \"Ejecutando: npm install\"\nprint_info \"Esto puede tomar 10-15 minutos...\"\necho \"\"\n\nif npm install >> \"$LOG_FILE\" 2>&1; then\n    print_success \"Dependencias instaladas correctamente\"\n    log_message \"npm install completado exitosamente\"\nelse\n    error_exit \"Falló la instalación de dependencias\"\nfi\necho \"\"\n\n# PASO 5: Instalar EAS CLI\nprint_header \"PASO 5: Instalando EAS CLI\"\nif ! command -v eas &> /dev/null; then\n    print_step \"Instalando EAS CLI...\"\n    npm install -g eas-cli >> \"$LOG_FILE\" 2>&1\n    if [ $? -eq 0 ]; then\n        print_success \"EAS CLI instalado\"\n        log_message \"EAS CLI instalado correctamente\"\n    else\n        print_warning \"No se pudo instalar EAS CLI, continuando con método alternativo\"\n        log_message \"ADVERTENCIA: EAS CLI no se instaló\"\n    fi\nelse\n    print_success \"EAS CLI ya está instalado: $(eas --version)\"\n    log_message \"EAS CLI encontrado: $(eas --version)\"\nfi\necho \"\"\n\n# PASO 6: Preparar configuración para Admin\nprint_header \"PASO 6: Preparando Configuración para Admin\"\nprint_step \"Usando configuración: app.json (Admin)\"\n\nif [ ! -f \"$PROJECT_DIR/app.json\" ]; then\n    error_exit \"app.json no encontrado en $PROJECT_DIR\"\nfi\n\nprint_success \"Configuración Admin lista\"\nlog_message \"Configuración Admin verificada\"\necho \"\"\n\n# PASO 7: Compilación\nprint_header \"PASO 7: Compilando Versión Admin\"\necho \"\"\necho -e \"${MAGENTA}╔═══════════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${MAGENTA}║                                                               ║${NC}\"\necho -e \"${MAGENTA}║         ${BUILD} COMPILACIÓN EN PROGRESO ${BUILD}                        ║${NC}\"\necho -e \"${MAGENTA}║                                                               ║${NC}\"\necho -e \"${MAGENTA}║     ${HOURGLASS} Esto puede tomar 30-40 minutos...                    ║${NC}\"\necho -e \"${MAGENTA}║                                                               ║${NC}\"\necho -e \"${MAGENTA}║     ${INFO} Mantén el dispositivo conectado a corriente             ║${NC}\"\necho -e \"${MAGENTA}║     ${INFO} No cierres Termux                                       ║${NC}\"\necho -e \"${MAGENTA}║                                                               ║${NC}\"\necho -e \"${MAGENTA}╚═══════════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\n\nprint_step \"Compilando con EAS...\"\nlog_message \"Iniciando compilación de APK Admin\"\n\nif eas build --platform android --local >> \"$LOG_FILE\" 2>&1; then\n    print_success \"Compilación completada exitosamente\"\n    log_message \"Compilación de APK Admin completada\"\nelse\n    print_warning \"Compilación con EAS falló, intentando método alternativo...\"\n    log_message \"ADVERTENCIA: Compilación con EAS falló\"\n    \n    print_step \"Intentando compilación con Gradle...\"\n    if npx expo prebuild --clean >> \"$LOG_FILE\" 2>&1; then\n        print_success \"Prebuild completado\"\n        log_message \"Prebuild completado\"\n        \n        if cd android && ./gradlew assembleRelease >> \"$LOG_FILE\" 2>&1; then\n            print_success \"Compilación con Gradle completada\"\n            log_message \"Compilación con Gradle completada\"\n            cd ..\n        else\n            error_exit \"Falló la compilación con Gradle\"\n        fi\n    else\n        error_exit \"Falló el prebuild\"\n    fi\nfi\n\necho \"\"\n\n# PASO 8: Buscar y copiar APK\nprint_header \"PASO 8: Localizando APK Compilado\"\n\n# Buscar APK en ubicaciones comunes\nAPK_FOUND=false\nAPK_FILE=\"\"\n\nif [ -f \"$PROJECT_DIR/dist/gestor-creditos-admin.apk\" ]; then\n    APK_FILE=\"$PROJECT_DIR/dist/gestor-creditos-admin.apk\"\n    APK_FOUND=true\nelif [ -f \"$PROJECT_DIR/android/app/build/outputs/apk/release/app-release.apk\" ]; then\n    APK_FILE=\"$PROJECT_DIR/android/app/build/outputs/apk/release/app-release.apk\"\n    APK_FOUND=true\nelif [ -f \"$PROJECT_DIR/android/app/build/outputs/bundle/release/app-release.aab\" ]; then\n    print_info \"Se generó un AAB en lugar de APK\"\n    print_info \"Ubicación: $PROJECT_DIR/android/app/build/outputs/bundle/release/app-release.aab\"\n    APK_FOUND=true\nelse\n    # Buscar recursivamente\n    APK_SEARCH=$(find \"$PROJECT_DIR\" -name \"*.apk\" -type f 2>/dev/null | head -1)\n    if [ -n \"$APK_SEARCH\" ]; then\n        APK_FILE=\"$APK_SEARCH\"\n        APK_FOUND=true\n    fi\nfi\n\nif [ \"$APK_FOUND\" = true ] && [ -n \"$APK_FILE\" ]; then\n    APK_SIZE=$(du -h \"$APK_FILE\" | cut -f1)\n    APK_FILENAME=$(basename \"$APK_FILE\")\n    \n    # Copiar a directorio de APKs\n    TIMESTAMP=$(date +%Y%m%d_%H%M%S)\n    NEW_APK_NAME=\"gestor-creditos-admin-$TIMESTAMP.apk\"\n    NEW_APK_PATH=\"$APK_DIR/$NEW_APK_NAME\"\n    \n    cp \"$APK_FILE\" \"$NEW_APK_PATH\"\n    \n    print_success \"APK encontrado y copiado\"\n    print_info \"Nombre original: $APK_FILENAME\"\n    print_info \"Nombre nuevo: $NEW_APK_NAME\"\n    print_info \"Tamaño: $APK_SIZE\"\n    print_info \"Ubicación: $NEW_APK_PATH\"\n    \n    log_message \"APK Admin copiado a: $NEW_APK_PATH\"\n    log_message \"Tamaño: $APK_SIZE\"\nelse\n    print_warning \"No se encontró APK compilado\"\n    print_info \"Buscando archivos de compilación...\"\n    find \"$PROJECT_DIR\" -name \"*.apk\" -o -name \"*.aab\" 2>/dev/null\n    log_message \"ADVERTENCIA: APK no encontrado\"\nfi\n\necho \"\"\n\n# PASO 9: Generar reporte\nprint_header \"PASO 9: Generando Reporte\"\n\nEND_TIME=$(date +%s)\nELAPSED=$((END_TIME - START_TIME))\nMINUTES=$((ELAPSED / 60))\nSECONDS=$((ELAPSED % 60))\n\ncat > \"$REPORT_FILE\" << EOF\n╔═══════════════════════════════════════════════════════════════╗\n║                                                               ║\n║           REPORTE DE COMPILACIÓN - VERSIÓN ADMIN              ║\n║                                                               ║\n╚═══════════════════════════════════════════════════════════════╝\n\n📱 INFORMACIÓN DE LA APLICACIÓN\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\nNombre: $APP_NAME\nVersión: $APP_VERSION\nPlataforma: Android (Termux)\nTipo: APK Compilado\n\n📊 INFORMACIÓN DE LA COMPILACIÓN\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\nFecha de compilación: $BUILD_DATE\nTiempo total: ${MINUTES}m ${SECONDS}s\nDirectorio del proyecto: $PROJECT_DIR\nDirectorio de APKs: $APK_DIR\n\n📁 ARCHIVOS GENERADOS\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\nEOF\n\nif [ -n \"$NEW_APK_PATH\" ] && [ -f \"$NEW_APK_PATH\" ]; then\n    echo \"✅ APK Admin:\" >> \"$REPORT_FILE\"\n    echo \"   Nombre: $NEW_APK_NAME\" >> \"$REPORT_FILE\"\n    echo \"   Ruta: $NEW_APK_PATH\" >> \"$REPORT_FILE\"\n    echo \"   Tamaño: $(du -h \"$NEW_APK_PATH\" | cut -f1)\" >> \"$REPORT_FILE\"\nelse\n    echo \"❌ APK no encontrado\" >> \"$REPORT_FILE\"\nfi\n\ncat >> \"$REPORT_FILE\" << EOF\n\n🔧 CARACTERÍSTICAS COMPILADAS\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n✅ Autenticación con JWT\n✅ Sistema de roles (Admin, Manager, User)\n✅ Dashboard interactivo\n✅ Gestión de deudores\n✅ Módulo de pagos a crédito\n✅ Reportes y gráficos\n✅ Notificaciones configurables\n✅ Búsqueda y filtrado en tiempo real\n✅ Diseño responsive\n✅ Paleta de colores profesional\n\n📋 PRÓXIMOS PASOS\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n1. Instalar APK en tu dispositivo:\n   adb install $NEW_APK_PATH\n\n2. O instalar manualmente:\n   - Copia el APK a tu dispositivo\n   - Abre el administrador de archivos\n   - Toca el APK para instalar\n\n3. Abre la aplicación en tu dispositivo\n\n4. Crea tu cuenta de administrador\n\n5. ¡Comienza a usar!\n\n📞 SOPORTE\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\nEmail: support@gestorcreditos.com\nDocumentación: TERMUX_PASO_A_PASO.md\nLogs: $LOG_FILE\n\n═══════════════════════════════════════════════════════════════\nFin del reporte - $(date '+%Y-%m-%d %H:%M:%S')\n═══════════════════════════════════════════════════════════════\nEOF\n\nprint_success \"Reporte generado\"\nprint_info \"Ubicación: $REPORT_FILE\"\nlog_message \"Reporte generado en: $REPORT_FILE\"\necho \"\"\n\n# PASO 10: Resumen final\nprint_header \"RESUMEN FINAL\"\necho \"\"\necho -e \"${GREEN}╔═══════════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${GREEN}║                                                               ║${NC}\"\necho -e \"${GREEN}║        ${SUCCESS} COMPILACIÓN COMPLETADA EXITOSAMENTE ${SUCCESS}                ║${NC}\"\necho -e \"${GREEN}║                                                               ║${NC}\"\necho -e \"${GREEN}╚═══════════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\n\necho -e \"${CYAN}Información de la Compilación:${NC}\"\necho -e \"  Aplicación: $APP_NAME\"\necho -e \"  Versión: $APP_VERSION\"\necho -e \"  Tiempo total: ${MINUTES}m ${SECONDS}s\"\necho -e \"  Fecha: $BUILD_DATE\"\necho \"\"\n\nif [ -n \"$NEW_APK_PATH\" ] && [ -f \"$NEW_APK_PATH\" ]; then\n    echo -e \"${CYAN}APK Generado:${NC}\"\n    echo -e \"  Nombre: $NEW_APK_NAME\"\n    echo -e \"  Tamaño: $(du -h \"$NEW_APK_PATH\" | cut -f1)\"\n    echo -e \"  Ubicación: $APK_DIR/\"\n    echo \"\"\n    echo -e \"${CYAN}Para instalar en tu dispositivo:${NC}\"\n    echo -e \"  ${YELLOW}adb install $NEW_APK_PATH${NC}\"\n    echo \"\"\nfi\n\necho -e \"${CYAN}Archivos Generados:${NC}\"\necho -e \"  Logs: $LOG_FILE\"\necho -e \"  Reporte: $REPORT_FILE\"\necho \"\"\n\necho -e \"${GREEN}${CHECK} ¡Todo completado! El APK está listo para instalar.${NC}\"\necho \"\"\n\nlog_message \"Compilación finalizada exitosamente\"\nlog_message \"═══════════════════════════════════════════════════════════════\"\n\necho -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\necho \"\"\n
